import React, { useCallback, useEffect, useId, useRef, useState } from 'react';
import './styles/search-input.css';

// ─────────────────────────────────────────────────────────────
//  SHARED TYPES
// ─────────────────────────────────────────────────────────────

export type SearchInputSize    = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
export type SearchInputVariant = 'outlined' | 'filled' | 'underline' | 'ghost';
export type SearchInputShape   = 'default' | 'pill' | 'square';
export type SearchInputStatus  = 'default' | 'error' | 'success' | 'warning';


// ─────────────────────────────────────────────────────────────
//  SEARCH INPUT  (basic, with clear, with kbd hint, loading)
// ─────────────────────────────────────────────────────────────

export interface SearchInputProps
  extends Omit<React.InputHTMLAttributes<HTMLInputElement>, 'size' | 'type' | 'onChange'> {
  /** Visual style family. Default: 'outlined' */
  variant?: SearchInputVariant;

  /** Size preset. Default: 'md' */
  size?: SearchInputSize;

  /** Border-radius shape. Default: 'default' (8px) */
  shape?: SearchInputShape;

  /** Validation status color. Default: 'default' */
  status?: SearchInputStatus;

  /** Show the magnifying glass icon on the left */
  showIcon?: boolean;

  /**
   * Show an animated × clear button in the right slot when the
   * input has a value. Calls `onChange('')` when clicked.
   */
  clearable?: boolean;

  /**
   * Keyboard shortcut hint shown in the right slot (e.g. "⌘K").
   * Hidden once the user starts typing.
   */
  shortcutHint?: string;

  /**
   * Show a loading spinner and bottom-bar animation.
   * Replaces the clear button while active.
   */
  loading?: boolean;

  /**
   * Autocomplete suggestion shown as ghost text after the cursor.
   * The component accepts the suggestion when the user presses Tab.
   */
  suggestion?: string;

  /** Controlled value */
  value?: string;

  /** Called on every change, receives the raw string value */
  onChange?: (value: string) => void;

  /** Extra class names added to the wrapper div */
  wrapperClassName?: string;

  /** Extra class names added to the <input> element */
  className?: string;
}

// Internal icon components
const SearchIcon = ({ size = 15 }: { size?: number }) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none"
    stroke="currentColor" strokeWidth="2.2" aria-hidden="true">
    <circle cx="11" cy="11" r="8" />
    <path d="m21 21-4.35-4.35" />
  </svg>
);

const ClearIcon = () => (
  <svg width="14" height="14" viewBox="0 0 24 24" fill="none"
    stroke="currentColor" strokeWidth="2.5" aria-hidden="true">
    <line x1="18" y1="6" x2="6" y2="18" />
    <line x1="6" y1="6" x2="18" y2="18" />
  </svg>
);

const ICON_SIZES: Record<SearchInputSize, number> = {
  xs: 12, sm: 13, md: 15, lg: 16, xl: 18,
};

const VARIANT_CLASS: Record<SearchInputVariant, string> = {
  outlined : '',
  filled   : 'si-filled',
  underline: 'si-underline',
  ghost    : 'si-ghost-input',
};

const STATUS_CLASS: Record<SearchInputStatus, string> = {
  default: '',
  error  : 'si-status-error',
  success: 'si-status-success',
  warning: 'si-status-warning',
};

export const SearchInput = React.forwardRef<HTMLInputElement, SearchInputProps>(
  (props, ref) => {
    const {
      variant         = 'outlined',
      size            = 'md',
      shape           = 'default',
      status          = 'default',
      showIcon        = true,
      clearable       = false,
      shortcutHint,
      loading         = false,
      suggestion      = '',
      value: valueProp,
      onChange,
      wrapperClassName = '',
      className        = '',
      placeholder      = 'Search…',
      disabled,
      onKeyDown,
      ...rest
    } = props;

    // Controlled / uncontrolled value
    const [internalValue, setInternalValue] = useState(valueProp ?? '');
    const value = valueProp !== undefined ? valueProp : internalValue;

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const v = e.target.value;
      if (valueProp === undefined) setInternalValue(v);
      onChange?.(v);
    };

    const handleClear = () => {
      if (valueProp === undefined) setInternalValue('');
      onChange?.('');
    };

    // Tab to accept suggestion
    const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Tab' && suggestion && suggestion.startsWith(value)) {
        e.preventDefault();
        const accepted = suggestion;
        if (valueProp === undefined) setInternalValue(accepted);
        onChange?.(accepted);
      }
      onKeyDown?.(e);
    };

    // Wrapper classes
    const showClear     = clearable && !loading && value.length > 0;
    const showKbd       = shortcutHint && !value && !loading;
    const hasRight      = loading || showClear || !!showKbd;
    const hasRightWide  = !!showKbd && !loading && !showClear;

    const wrapClasses = [
      'si-wrap',
      showIcon  ? 'has-left'       : '',
      hasRight  ? (hasRightWide ? 'has-right-wide' : 'has-right') : '',
      loading   ? 'is-loading'     : '',
      wrapperClassName,
    ].filter(Boolean).join(' ');

    const inputClasses = [
      'si',
      `si-${size}`,
      VARIANT_CLASS[variant],
      shape !== 'default' ? `si-${shape}` : '',
      STATUS_CLASS[status],
      className,
    ].filter(Boolean).join(' ');

    const iconStatusClass =
      status === 'error'   ? 'si-icon-error'   :
      status === 'success' ? 'si-icon-success'  :
      status === 'warning' ? 'si-icon-warning'  : '';

    // Suggestion ghost text
    const ghostText = suggestion && value && suggestion.startsWith(value)
      ? suggestion.slice(value.length)
      : '';

    return (
      <div className={wrapClasses}>
        <input
          ref={ref}
          type="search"
          className={inputClasses}
          value={value}
          placeholder={placeholder}
          disabled={disabled || loading}
          onChange={handleChange}
          onKeyDown={handleKeyDown}
          aria-busy={loading}
          {...rest}
        />

        {/* Left icon */}
        {showIcon && (
          <span className={`si-icon-left ${iconStatusClass}`} aria-hidden="true">
            <SearchIcon size={ICON_SIZES[size]} />
          </span>
        )}

        {/* Autocomplete ghost */}
        {ghostText && (
          <span className="si-suggestion" aria-hidden="true">
            <span style={{ opacity: 0 }}>{value}</span>
            <span className="si-suggestion-ghost">{ghostText}</span>
          </span>
        )}

        {/* Right slot */}
        {hasRight && (
          <span className="si-right">
            {loading && (
              <span className="si-spinner" role="status" aria-label="Loading" />
            )}
            {showClear && (
              <button
                type="button"
                className="si-clear"
                onClick={handleClear}
                aria-label="Clear search"
                tabIndex={-1}
              >
                <ClearIcon />
              </button>
            )}
            {showKbd && (
              <span className="si-kbd" aria-hidden="true">{shortcutHint}</span>
            )}
          </span>
        )}
      </div>
    );
  }
);

SearchInput.displayName = 'SearchInput';


// ─────────────────────────────────────────────────────────────
//  COMMAND PALETTE TYPES
// ─────────────────────────────────────────────────────────────

export interface CommandItem {
  id       : string;
  name     : string;
  /** Secondary descriptor shown below the name */
  subtitle?: string;
  /** Optional keyboard shortcut label shown on the right */
  shortcut?: string;
  /** Icon element rendered in the item icon box */
  icon?    : React.ReactNode;
  /** Called when the user selects this item */
  onSelect?: () => void;
}

export interface CommandGroup {
  /** Group heading label */
  label: string;
  items: CommandItem[];
}

export interface CommandPaletteProps {
  /** Whether the palette is visible */
  open: boolean;
  /** Called when the user presses Esc or clicks the backdrop */
  onClose: () => void;
  /** Data to display, organised into groups */
  groups: CommandGroup[];
  /** Input placeholder text */
  placeholder?: string;
  /**
   * Custom filter function. Receives the query string and the full groups array.
   * Return the filtered groups. Defaults to case-insensitive substring match
   * on item name + subtitle.
   */
  filterFn?: (query: string, groups: CommandGroup[]) => CommandGroup[];
  /** Called when the user selects an item (after onSelect on the item fires) */
  onSelect?: (item: CommandItem) => void;
}

// ─────────────────────────────────────────────────────────────
//  DEFAULT FILTER
// ─────────────────────────────────────────────────────────────

function defaultFilter(query: string, groups: CommandGroup[]): CommandGroup[] {
  if (!query.trim()) return groups;
  const q = query.toLowerCase();
  return groups
    .map(g => ({
      ...g,
      items: g.items.filter(it =>
        it.name.toLowerCase().includes(q) ||
        (it.subtitle ?? '').toLowerCase().includes(q)
      ),
    }))
    .filter(g => g.items.length > 0);
}

// Highlight matching substring
function HighlightMatch({ text, query }: { text: string; query: string }) {
  if (!query) return <>{text}</>;
  const idx = text.toLowerCase().indexOf(query.toLowerCase());
  if (idx < 0) return <>{text}</>;
  return (
    <>
      {text.slice(0, idx)}
      <span className="si-match-hl">{text.slice(idx, idx + query.length)}</span>
      {text.slice(idx + query.length)}
    </>
  );
}


// ─────────────────────────────────────────────────────────────
//  COMMAND PALETTE COMPONENT
// ─────────────────────────────────────────────────────────────

/**
 * CommandPalette
 *
 * Renders a floating search-driven command palette.
 * Manages its own internal query state and keyboard navigation.
 *
 * @example
 * const [open, setOpen] = useState(false);
 *
 * // Open with ⌘K
 * useEffect(() => {
 *   const handler = (e: KeyboardEvent) => {
 *     if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
 *       e.preventDefault();
 *       setOpen(v => !v);
 *     }
 *   };
 *   window.addEventListener('keydown', handler);
 *   return () => window.removeEventListener('keydown', handler);
 * }, []);
 *
 * <CommandPalette
 *   open={open}
 *   onClose={() => setOpen(false)}
 *   groups={myGroups}
 *   onSelect={(item) => console.log('selected', item)}
 * />
 */
export function CommandPalette({
  open,
  onClose,
  groups,
  placeholder = 'Search commands, pages, actions…',
  filterFn    = defaultFilter,
  onSelect,
}: CommandPaletteProps) {
  const [query,     setQuery]     = useState('');
  const [activeIdx, setActiveIdx] = useState(0);
  const inputRef = useRef<HTMLInputElement>(null);
  const listRef  = useRef<HTMLDivElement>(null);
  const id = useId();

  // Focus input when palette opens; reset on close
  useEffect(() => {
    if (open) {
      setQuery('');
      setActiveIdx(0);
      requestAnimationFrame(() => inputRef.current?.focus());
    }
  }, [open]);

  // Flatten filtered items for keyboard navigation
  const filteredGroups = filterFn(query, groups);
  const flatItems      = filteredGroups.flatMap(g => g.items);

  const select = useCallback(
    (item: CommandItem) => {
      item.onSelect?.();
      onSelect?.(item);
      onClose();
    },
    [onSelect, onClose]
  );

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Escape') { onClose(); return; }
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setActiveIdx(i => Math.min(i + 1, flatItems.length - 1));
    }
    if (e.key === 'ArrowUp') {
      e.preventDefault();
      setActiveIdx(i => Math.max(i - 1, 0));
    }
    if (e.key === 'Enter' && flatItems[activeIdx]) {
      e.preventDefault();
      select(flatItems[activeIdx]);
    }
  };

  // Scroll active item into view
  useEffect(() => {
    const el = listRef.current?.querySelector<HTMLDivElement>('.si-cmd-item.is-active');
    el?.scrollIntoView({ block: 'nearest' });
  }, [activeIdx]);

  if (!open) return null;

  let globalIdx = 0;

  return (
    <div
      className="si-cmd-overlay"
      onClick={e => { if (e.target === e.currentTarget) onClose(); }}
      role="dialog"
      aria-modal="true"
      aria-label="Command palette"
    >
      <div className="si-cmd-box" onKeyDown={handleKeyDown}>
        {/* Input row */}
        <div className="si-cmd-input-row">
          <SearchIcon size={16} />
          <input
            ref={inputRef}
            className="si-cmd-input"
            type="text"
            placeholder={placeholder}
            value={query}
            onChange={e => { setQuery(e.target.value); setActiveIdx(0); }}
            autoComplete="off"
            spellCheck={false}
            aria-autocomplete="list"
            aria-controls={`${id}-results`}
            aria-activedescendant={
              flatItems[activeIdx] ? `${id}-item-${flatItems[activeIdx].id}` : undefined
            }
          />
          {query && (
            <button
              type="button"
              className="si-cmd-clear"
              onClick={() => { setQuery(''); setActiveIdx(0); inputRef.current?.focus(); }}
              aria-label="Clear query"
            >
              <ClearIcon />
            </button>
          )}
          <span className="si-kbd" aria-label="Press Escape to close">esc</span>
        </div>

        {/* Results */}
        <div
          ref={listRef}
          className="si-cmd-results"
          id={`${id}-results`}
          role="listbox"
        >
          {flatItems.length === 0 ? (
            <div className="si-cmd-empty">
              {query ? `No results for "${query}"` : 'No commands available'}
            </div>
          ) : (
            filteredGroups.map(group => (
              <div key={group.label}>
                <div className="si-cmd-group" role="presentation">{group.label}</div>
                {group.items.map(item => {
                  const idx       = globalIdx++;
                  const isActive  = idx === activeIdx;
                  return (
                    <div
                      key={item.id}
                      id={`${id}-item-${item.id}`}
                      className={`si-cmd-item${isActive ? ' is-active' : ''}`}
                      role="option"
                      aria-selected={isActive}
                      onMouseEnter={() => setActiveIdx(idx)}
                      onClick={() => select(item)}
                    >
                      {item.icon && (
                        <div className="si-cmd-item-icon">{item.icon}</div>
                      )}
                      <div className="si-cmd-item-body">
                        <div className="si-cmd-item-name">
                          <HighlightMatch text={item.name} query={query} />
                        </div>
                        {item.subtitle && (
                          <div className="si-cmd-item-sub">
                            <HighlightMatch text={item.subtitle} query={query} />
                          </div>
                        )}
                      </div>
                      {item.shortcut && (
                        <span className="si-cmd-item-kbd">{item.shortcut}</span>
                      )}
                    </div>
                  );
                })}
              </div>
            ))
          )}
        </div>

        {/* Footer hints */}
        <div className="si-cmd-footer" aria-hidden="true">
          <div className="si-cmd-hint">
            <span className="si-kbd">↑↓</span> navigate
          </div>
          <div className="si-cmd-sep" />
          <div className="si-cmd-hint">
            <span className="si-kbd">↵</span> select
          </div>
          <div className="si-cmd-sep" />
          <div className="si-cmd-hint">
            <span className="si-kbd">esc</span> close
          </div>
        </div>
      </div>
    </div>
  );
}


// ─────────────────────────────────────────────────────────────
//  useCommandPalette  — convenience hook
//
//  Handles the ⌘K / Ctrl+K toggle shortcut for you.
//
//  @example
//  const { open, setOpen, toggle } = useCommandPalette();
//  <CommandPalette open={open} onClose={() => setOpen(false)} groups={...} />
// ─────────────────────────────────────────────────────────────
export function useCommandPalette(shortcut = 'k') {
  const [open, setOpen] = useState(false);

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === shortcut) {
        e.preventDefault();
        setOpen(v => !v);
      }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [shortcut]);

  return { open, setOpen, toggle: () => setOpen(v => !v) };
}

export default SearchInput;

/* ============================================================
   search-input.css
   ============================================================

   CLASS ANATOMY:
   <div class="si-wrap  [has-left]  [has-right]  [has-right-wide]  [is-loading]">
     <input class="si  [size]  [variant]  [shape]  [status]" />
     <span class="si-icon-left">   ...icon   </span>   (optional)
     <span class="si-right">       ...btns   </span>   (optional)
   </div>

   SIZES    : si-xs | si-sm | si-md (default) | si-lg | si-xl
   VARIANTS : (default outlined) | si-filled | si-underline | si-ghost-input
   SHAPES   : (default 8px) | si-pill | si-square
   STATUS   : si-status-error | si-status-success | si-status-warning
   ============================================================ */

/* ── CSS TOKENS ─────────────────────────────────────────── */
:root {
  --si-font-family    : -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --si-font-weight    : 400;
  --si-transition     : border-color 0.15s ease, box-shadow 0.15s ease, background 0.15s ease;

  /* radius scale */
  --si-radius-default : 8px;
  --si-radius-pill    : 999px;
  --si-radius-square  : 4px;

  /* colors */
  --si-border         : #d1d5db;
  --si-border-hover   : #9ca3af;
  --si-border-focus   : #2563eb;
  --si-ring-focus     : rgba(37, 99, 235, 0.15);
  --si-bg             : #ffffff;
  --si-bg-filled      : #f3f4f6;
  --si-bg-filled-hover: #e5e7eb;
  --si-bg-disabled    : #f9fafb;
  --si-text           : #111827;
  --si-placeholder    : #9ca3af;
  --si-icon-default   : #9ca3af;
  --si-icon-focus     : #2563eb;

  /* status */
  --si-border-error   : #dc2626;
  --si-ring-error     : rgba(220, 38, 38, 0.15);
  --si-icon-error     : #dc2626;
  --si-border-success : #16a34a;
  --si-ring-success   : rgba(22, 163, 74, 0.15);
  --si-icon-success   : #16a34a;
  --si-border-warning : #d97706;
  --si-ring-warning   : rgba(217, 119, 6, 0.15);
  --si-icon-warning   : #d97706;

  /* surface/neutral (reused from Button if present) */
  --si-surface        : #f3f4f6;
  --si-surface-hover  : #e5e7eb;
}


/* ══════════════════════════════════════════════════════════
   WRAPPER
   Always wraps the input. Enables absolute-positioned slots.
══════════════════════════════════════════════════════════ */
.si-wrap {
  position   : relative;
  display    : inline-flex;
  align-items: center;
  width      : 100%;
}

/* shift input padding when slots are active */
.si-wrap.has-left  .si { padding-left : 36px; }
.si-wrap.has-right .si { padding-right: 36px; }
.si-wrap.has-right-wide .si { padding-right: 72px; }

/* underline variant needs flush left */
.si-wrap.has-left .si.si-underline { padding-left: 28px !important; }


/* ══════════════════════════════════════════════════════════
   BASE INPUT
══════════════════════════════════════════════════════════ */
.si {
  width           : 100%;
  height          : 38px;
  padding         : 0 12px;
  font-family     : var(--si-font-family);
  font-size       : 14px;
  font-weight     : var(--si-font-weight);
  color           : var(--si-text);
  background      : var(--si-bg);
  border          : 1px solid var(--si-border);
  border-radius   : var(--si-radius-default);
  outline         : none;
  transition      : var(--si-transition);
  box-sizing      : border-box;
  -webkit-appearance: none;
  appearance      : none;
}

/* remove native search cancel button */
.si[type="search"]::-webkit-search-cancel-button,
.si[type="search"]::-webkit-search-decoration { display: none; }

.si::placeholder { color: var(--si-placeholder); }

.si:hover:not(:disabled) { border-color: var(--si-border-hover); }

.si:focus {
  border-color: var(--si-border-focus);
  box-shadow  : 0 0 0 3px var(--si-ring-focus);
}

.si:disabled {
  opacity   : 0.5;
  cursor    : not-allowed;
  background: var(--si-bg-disabled);
}


/* ══════════════════════════════════════════════════════════
   SIZES
══════════════════════════════════════════════════════════ */
.si-xs {
  height       : 26px;
  padding      : 0 8px;
  font-size    : 12px;
  border-radius: var(--si-radius-square);
}

.si-sm {
  height   : 32px;
  padding  : 0 10px;
  font-size: 13px;
}

.si-md {
  height   : 38px;
  padding  : 0 12px;
  font-size: 14px;
}

.si-lg {
  height   : 44px;
  padding  : 0 16px;
  font-size: 15px;
}

.si-xl {
  height   : 52px;
  padding  : 0 18px;
  font-size: 16px;
}

/* icon slot sizing per size */
.si-wrap.has-left .si-xs { padding-left: 30px; }
.si-wrap.has-left .si-sm { padding-left: 32px; }
.si-wrap.has-left .si-md { padding-left: 36px; }
.si-wrap.has-left .si-lg { padding-left: 40px; }
.si-wrap.has-left .si-xl { padding-left: 44px; }

.si-wrap.has-right .si-xs { padding-right: 30px; }
.si-wrap.has-right .si-sm { padding-right: 32px; }
.si-wrap.has-right .si-md { padding-right: 36px; }
.si-wrap.has-right .si-lg { padding-right: 40px; }
.si-wrap.has-right .si-xl { padding-right: 44px; }


/* ══════════════════════════════════════════════════════════
   SHAPES
══════════════════════════════════════════════════════════ */
.si-pill   { border-radius: var(--si-radius-pill)   !important; }
.si-square { border-radius: var(--si-radius-square) !important; }


/* ══════════════════════════════════════════════════════════
   VARIANTS
══════════════════════════════════════════════════════════ */

/* filled — tinted background, no visible border */
.si-filled {
  background  : var(--si-bg-filled);
  border-color: transparent;
}
.si-filled:hover:not(:disabled) {
  background  : var(--si-bg-filled-hover);
  border-color: transparent;
}
.si-filled:focus {
  background  : var(--si-bg);
  border-color: var(--si-border-focus);
}

/* underline — bottom border only */
.si-underline {
  border-radius: 0;
  border       : none;
  border-bottom: 1.5px solid var(--si-border);
  background   : transparent;
  padding-left : 0 !important;
  padding-right: 0 !important;
}
.si-underline:hover:not(:disabled) { border-bottom-color: var(--si-border-hover); }
.si-underline:focus {
  border-bottom-color: var(--si-border-focus);
  box-shadow         : none;
}

/* ghost — invisible until hover/focus */
.si-ghost-input {
  border-color: transparent;
  background  : transparent;
}
.si-ghost-input:hover:not(:disabled) {
  background: var(--si-surface);
}
.si-ghost-input:focus {
  border-color: var(--si-border-focus);
  background  : var(--si-bg);
}


/* ══════════════════════════════════════════════════════════
   STATUS COLORS
══════════════════════════════════════════════════════════ */
.si-status-error {
  border-color: var(--si-border-error);
}
.si-status-error:focus {
  border-color: var(--si-border-error);
  box-shadow  : 0 0 0 3px var(--si-ring-error);
}

.si-status-success {
  border-color: var(--si-border-success);
}
.si-status-success:focus {
  border-color: var(--si-border-success);
  box-shadow  : 0 0 0 3px var(--si-ring-success);
}

.si-status-warning {
  border-color: var(--si-border-warning);
}
.si-status-warning:focus {
  border-color: var(--si-border-warning);
  box-shadow  : 0 0 0 3px var(--si-ring-warning);
}


/* ══════════════════════════════════════════════════════════
   LEFT ICON SLOT
══════════════════════════════════════════════════════════ */
.si-icon-left {
  position       : absolute;
  left           : 10px;
  top            : 50%;
  transform      : translateY(-50%);
  color          : var(--si-icon-default);
  display        : flex;
  align-items    : center;
  pointer-events : none;
  transition     : color 0.15s ease;
  z-index        : 1;
}

/* icon follows focus color */
.si-wrap:focus-within .si-icon-left { color: var(--si-icon-focus); }

/* status icon colors */
.si-icon-left.si-icon-error   { color: var(--si-icon-error);   }
.si-icon-left.si-icon-success { color: var(--si-icon-success); }
.si-icon-left.si-icon-warning { color: var(--si-icon-warning); }

/* size-adjusted icon position */
.si-wrap.has-left .si-xs ~ .si-icon-left,
.si-wrap .si-xs + .si-icon-left { left: 8px; }
.si-wrap.has-left .si-lg ~ .si-icon-left,
.si-wrap .si-lg + .si-icon-left { left: 12px; }
.si-wrap.has-left .si-xl ~ .si-icon-left,
.si-wrap .si-xl + .si-icon-left { left: 14px; }


/* ══════════════════════════════════════════════════════════
   RIGHT SLOT  (clear button, spinner, keyboard hint)
══════════════════════════════════════════════════════════ */
.si-right {
  position   : absolute;
  right      : 8px;
  top        : 50%;
  transform  : translateY(-50%);
  display    : flex;
  align-items: center;
  gap        : 4px;
  z-index    : 1;
}

/* clear button */
.si-clear {
  background   : none;
  border       : none;
  cursor       : pointer;
  padding      : 2px;
  border-radius: 4px;
  color        : var(--si-icon-default);
  display      : flex;
  align-items  : center;
  transition   : color 0.12s ease, background 0.12s ease;
  line-height  : 1;
}
.si-clear:hover {
  color     : var(--si-text);
  background: var(--si-surface);
}
.si-clear:focus-visible {
  outline   : none;
  box-shadow: 0 0 0 2px var(--si-ring-focus);
}

/* keyboard shortcut badge */
.si-kbd {
  display       : inline-flex;
  align-items   : center;
  gap           : 2px;
  font-family   : ui-monospace, 'Cascadia Code', 'Fira Code', monospace;
  font-size     : 11px;
  color         : var(--si-icon-default);
  background    : var(--si-surface);
  border        : 0.5px solid var(--si-border);
  border-radius : 4px;
  padding       : 2px 5px;
  white-space   : nowrap;
  pointer-events: none;
}

/* loading spinner */
.si-spinner {
  display          : inline-block;
  width            : 14px;
  height           : 14px;
  border           : 2px solid var(--si-icon-default);
  border-top-color : transparent;
  border-radius    : 50%;
  animation        : si-spin 0.7s linear infinite;
  flex-shrink      : 0;
}

@keyframes si-spin {
  to { transform: rotate(360deg); }
}


/* ══════════════════════════════════════════════════════════
   LOADING BAR  (animated bottom border on wrapper)
   Add class `is-loading` to .si-wrap
══════════════════════════════════════════════════════════ */
.si-wrap.is-loading {
  overflow: hidden;
}

.si-wrap.is-loading::after {
  content      : '';
  position     : absolute;
  bottom       : -1px;
  left         : 0;
  height       : 2px;
  background   : var(--si-border-focus);
  border-radius: 1px;
  animation    : si-loadbar 1.4s ease-in-out infinite;
}

@keyframes si-loadbar {
  0%   { width: 0%;   left: 0;    }
  50%  { width: 60%;  left: 20%;  }
  100% { width: 0%;   left: 100%; }
}


/* ══════════════════════════════════════════════════════════
   INLINE AUTOCOMPLETE SUGGESTION
   Stack the input and suggestion absolutely in the wrapper.
   The suggestion div shows ghost text.
══════════════════════════════════════════════════════════ */
.si-suggestion-wrap {
  position: relative;
}

.si-suggestion {
  position      : absolute;
  inset         : 0;
  display       : flex;
  align-items   : center;
  pointer-events: none;
  font-family   : var(--si-font-family);
  font-size     : 14px;
  padding       : 0 12px;
  white-space   : nowrap;
  overflow      : hidden;
  z-index       : 0;
}

.si-suggestion-ghost {
  color  : var(--si-placeholder);
  opacity: 0.7;
}

/* the actual input sits above */
.si-suggestion-wrap .si {
  position  : relative;
  z-index   : 1;
  background: transparent;
}


/* ══════════════════════════════════════════════════════════
   COMMAND PALETTE
══════════════════════════════════════════════════════════ */

/* backdrop overlay — wrap this around .si-cmd-box */
.si-cmd-overlay {
  position        : fixed;
  inset           : 0;
  background      : rgba(0, 0, 0, 0.45);
  display         : flex;
  align-items     : flex-start;
  justify-content : center;
  padding-top     : 80px;
  z-index         : 9999;
  animation       : si-fade-in 0.1s ease;
}

@keyframes si-fade-in {
  from { opacity: 0; }
  to   { opacity: 1; }
}

/* dialog box */
.si-cmd-box {
  background   : var(--si-bg);
  border       : 0.5px solid var(--si-border);
  border-radius: 12px;
  width        : 100%;
  max-width    : 560px;
  max-height   : 60vh;
  display      : flex;
  flex-direction: column;
  overflow     : hidden;
  box-shadow   : 0 20px 60px rgba(0, 0, 0, 0.15);
  animation    : si-slide-in 0.12s ease;
}

@keyframes si-slide-in {
  from { transform: translateY(-8px); opacity: 0; }
  to   { transform: translateY(0);    opacity: 1; }
}

/* top input row */
.si-cmd-input-row {
  display    : flex;
  align-items: center;
  gap        : 10px;
  padding    : 12px 16px;
  border-bottom: 0.5px solid var(--si-border);
  flex-shrink: 0;
}

.si-cmd-input {
  flex       : 1;
  border     : none;
  outline    : none;
  font-size  : 15px;
  background : transparent;
  color      : var(--si-text);
  font-family: var(--si-font-family);
  min-width  : 0;
}
.si-cmd-input::placeholder { color: var(--si-placeholder); }

.si-cmd-clear {
  background   : none;
  border       : none;
  cursor       : pointer;
  color        : var(--si-icon-default);
  display      : flex;
  align-items  : center;
  border-radius: 4px;
  padding      : 2px;
  transition   : color 0.12s, background 0.12s;
}
.si-cmd-clear:hover {
  color     : var(--si-text);
  background: var(--si-surface);
}

/* scrollable results area */
.si-cmd-results {
  flex      : 1;
  overflow-y: auto;
  padding   : 4px 0;
}

/* group label */
.si-cmd-group {
  font-size     : 11px;
  font-weight   : 500;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color         : var(--si-icon-default);
  padding       : 10px 16px 4px;
}

/* result row */
.si-cmd-item {
  display    : flex;
  align-items: center;
  gap        : 10px;
  padding    : 7px 16px;
  cursor     : pointer;
  transition : background 0.1s;
  outline    : none;
}
.si-cmd-item:hover,
.si-cmd-item[aria-selected="true"],
.si-cmd-item.is-active {
  background: var(--si-surface);
}

.si-cmd-item-icon {
  width        : 28px;
  height       : 28px;
  border-radius: 6px;
  background   : var(--si-surface);
  border       : 0.5px solid var(--si-border);
  display      : flex;
  align-items  : center;
  justify-content: center;
  flex-shrink  : 0;
  color        : var(--si-icon-default);
  transition   : background 0.1s;
}
.si-cmd-item.is-active .si-cmd-item-icon {
  background: var(--si-bg-filled-hover);
}

.si-cmd-item-body {
  flex    : 1;
  min-width: 0;
}
.si-cmd-item-name {
  font-size  : 13px;
  font-weight: 500;
  color      : var(--si-text);
}
.si-cmd-item-sub {
  font-size    : 12px;
  color        : var(--si-icon-default);
  white-space  : nowrap;
  overflow     : hidden;
  text-overflow: ellipsis;
}

.si-cmd-item-kbd {
  font-family  : ui-monospace, monospace;
  font-size    : 11px;
  color        : var(--si-icon-default);
  background   : var(--si-surface);
  border       : 0.5px solid var(--si-border);
  border-radius: 4px;
  padding      : 2px 6px;
  margin-left  : auto;
  flex-shrink  : 0;
}

/* no results */
.si-cmd-empty {
  padding   : 32px 16px;
  text-align: center;
  font-size : 13px;
  color     : var(--si-icon-default);
}

/* footer hints */
.si-cmd-footer {
  display    : flex;
  align-items: center;
  gap        : 12px;
  padding    : 8px 16px;
  border-top : 0.5px solid var(--si-border);
  background : var(--si-surface);
  flex-shrink: 0;
}
.si-cmd-hint {
  display    : flex;
  align-items: center;
  gap        : 4px;
  font-size  : 11px;
  color      : var(--si-icon-default);
}
.si-cmd-sep {
  width     : 0.5px;
  height    : 12px;
  background: var(--si-border);
}

/* match highlight */
.si-match-hl {
  color      : #2563eb;
  font-weight: 500;
}


/* ══════════════════════════════════════════════════════════
   DARK MODE
══════════════════════════════════════════════════════════ */
@media (prefers-color-scheme: dark) {
  :root {
    --si-border         : #374151;
    --si-border-hover   : #4b5563;
    --si-bg             : #111827;
    --si-bg-filled      : #1f2937;
    --si-bg-filled-hover: #374151;
    --si-bg-disabled    : #1f2937;
    --si-text           : #f9fafb;
    --si-placeholder    : #6b7280;
    --si-icon-default   : #6b7280;
    --si-surface        : #1f2937;
    --si-surface-hover  : #374151;
  }
}
